-- Cadastro em lote de fornecedores/beneficiários (planilha "Cadastro Fornecedores.xlsx")
-- ON CONFLICT (documento) DO NOTHING: se já existir uma parte com o mesmo
-- CPF/CNPJ (cadastrada manualmente antes), a linha da planilha é ignorada
-- em vez de sobrescrever dados já ajustados na tela de Fornecedores.
ON CONFLICT (documento) WHERE documento IS NOT NULL DO NOTHING;

-- Verificação
SELECT count(*) AS total_partes FROM financeiro_partes;
